const resp = $input.first().json;
const rows = resp.data || resp.rows || resp || [];
return rows.map(r => ({ json: r }));

const contracts = $input.all().map(i => i.json);
const results = [];
const tokenMap = {
  '$SUPERMEMORY_TOKEN': $vars.SUPERMEMORY_TOKEN || '',
  '$KEY_MASTER': $vars.key_master || '',
  '$N8N_INTERNAL_API_KEY': $vars.N8N_INTERNAL_API_KEY || ''
};

// Contract overrides — fixes for rows that can't be updated via API yet
const overrides = {
  'ascend_mcp_server/mcp_sse': { url: 'https://mcp.ascendgtm.net/health', endpoint_name: 'health' },
  'n8n_gateway/gateway_routing': { url: 'https://mmurawala.app.n8n.cloud/webhook/orchestrate-v2', test_body: '{"domain":"handover","action":"list_variables","client":"system","params":{}}' },
  'supermemory/graph_viewport_v3': { expected_keys: '' }
};

for (const c of contracts) {
  // Apply overrides
  const key = c.service + '/' + c.endpoint_name;
  if (overrides[key]) { Object.assign(c, overrides[key]); }

  const start = Date.now();
  let status = 'PASS';
  let detail = '';
  let httpStatus = 0;
  let schemaOk = true;

  try {
    const headers = { 'Content-Type': 'application/json' };

    if (c.auth_header) {
      const parts = c.auth_header.split(' ');
      if (parts[0] === 'Bearer') {
        headers['Authorization'] = 'Bearer ' + (tokenMap[parts[1]] || parts[1]);
      } else if (parts[0] === 'x-api-key') {
        headers['x-api-key'] = tokenMap[parts[1]] || parts[1];
      }
    }

    const reqOpts = {
      method: c.method || 'GET',
      uri: c.url,
      headers,
      resolveWithFullResponse: true,
      simple: false,
      timeout: 15000
    };

    if (c.test_body && c.method !== 'GET') {
      reqOpts.body = c.test_body;
    }

    const resp = await this.helpers.request(reqOpts);
    httpStatus = resp.statusCode;
    const latency = Date.now() - start;

    if (c.expected_status && httpStatus !== Number(c.expected_status)) {
      status = 'FAIL';
      detail = 'Expected HTTP ' + c.expected_status + ', got ' + httpStatus;
    }

    if (status === 'PASS' && c.expected_keys && httpStatus < 400) {
      try {
        const body = typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
        const keys = c.expected_keys.split(',').map(k => k.trim()).filter(k => k);
        const missing = keys.filter(k => !(k in body));
        if (missing.length > 0) {
          status = 'FAIL';
          detail = 'Missing keys: ' + missing.join(', ');
          schemaOk = false;
        }
      } catch (e) {
        status = 'FAIL';
        detail = 'Response not valid JSON';
        schemaOk = false;
      }
    }

    if (status === 'PASS') detail = 'HTTP ' + httpStatus + ' in ' + latency + 'ms';

    results.push({ service: c.service, endpoint: c.endpoint_name, status, detail, http_status: httpStatus, latency_ms: latency, critical: !!c.critical, schema_ok: schemaOk });
  } catch (e) {
    results.push({ service: c.service, endpoint: c.endpoint_name, status: 'FAIL', detail: String(e.message || e).substring(0, 150), http_status: 0, latency_ms: Date.now() - start, critical: !!c.critical, schema_ok: false });
  }
}

const failed = results.filter(r => r.status === 'FAIL');
const criticalFailed = failed.filter(r => r.critical);
const allOk = failed.length === 0;

let severity = ':white_check_mark:';
let headline = 'All ' + results.length + ' contracts passing';
if (criticalFailed.length > 0) { severity = ':rotating_light:'; headline = criticalFailed.length + ' CRITICAL contract(s) FAILED'; }
else if (failed.length > 0) { severity = ':warning:'; headline = failed.length + ' non-critical contract(s) failed'; }

const lines = results.map(r => '• ' + (r.status === 'PASS' ? '✅' : (r.critical ? '🔴' : '🟡')) + ' ' + r.service + '/' + r.endpoint + ': ' + r.detail).join('\n');
const slackText = severity + ' *Integration Contract Test* — ' + headline + '\n' + lines;

// Debug: token resolution lengths
const debug = { sm_token_len: (tokenMap['$SUPERMEMORY_TOKEN'] || '').length, km_token_len: (tokenMap['$KEY_MASTER'] || '').length };

return [{ json: { results, failed, criticalFailed, allOk, total: results.length, failed_count: failed.length, critical_failed_count: criticalFailed.length, slack_text: slackText, timestamp: new Date().toISOString(), debug } }];

const data = $json;
try {
  const logBody = JSON.stringify({
    domain: 'handover',
    action: 'datatable_insert',
    client: 'system',
    params: {
      table_id: 'kqKrSqKSsu8UbU89',
      rows: [{
        timestamp: data.timestamp || new Date().toISOString(),
        category: 'contract_test',
        domain: 'platform',
        summary: 'Contract test: ' + (data.total||0) + ' tested, ' + (data.failed_count||0) + ' failed (' + (data.critical_failed_count||0) + ' critical)',
        details: JSON.stringify((data.failed || []).map(f => f.service + '/' + f.endpoint + ': ' + f.detail)),
        session_id: 'automated'
      }]
    }
  });
  await this.helpers.request({
    method: 'POST',
    uri: 'https://mmurawala.app.n8n.cloud/webhook/mcp-gateway',
    headers: { 'Content-Type': 'application/json', 'x-api-key': $vars.key_master },
    body: logBody,
    timeout: 10000
  });
} catch (e) { /* non-critical logging */ }
return [{ json: { logged: true, total: data.total, failed: data.failed_count } }];
